import "./Login.css";
import { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

export default function Login() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [loading, setLoading] = useState(false);
  const [errorMessage, setErrorMessage] = useState("");
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setErrorMessage("");

    // Validate inputs
    if (!email.trim() || !password.trim()) {
      setErrorMessage("Email and password are required");
      setLoading(false);
      return;
    }

    console.log("Attempting login with:", { email }); // Don't log password

    try {
      const response = await axios.post(
        "http://127.0.0.1:8000/api/login/",
        {
          email: email,
          password: password,
        },
        {
          headers: {
            "Content-Type": "application/json",
          },
          timeout: 10000, // 10 second timeout
        }
      );

      console.log("Login response:", response.data);

      // Check if response has required fields
      if (response.data.token && response.data.user_id) {
        // ✅ SAVE LOGIN DATA (VERY IMPORTANT)
        localStorage.setItem("token", response.data.token);
        localStorage.setItem("user_id", response.data.user_id);
        localStorage.setItem("user_name", response.data.name || "");
        localStorage.setItem("user_email", response.data.email || email);

        alert("Login successful ✅");
        navigate("/recipes");
      } else {
        console.error("Invalid response format:", response.data);
        setErrorMessage("Server returned invalid data format");
      }
    } catch (error) {
      console.error("Login error details:", {
        message: error.message,
        response: error.response?.data,
        status: error.response?.status,
        headers: error.response?.headers,
      });

      // Handle different error types
      if (error.code === "ECONNABORTED") {
        setErrorMessage("Connection timeout. Please try again.");
      } else if (!error.response) {
        setErrorMessage("Network error. Cannot connect to server.");
      } else if (error.response.status === 401) {
        setErrorMessage("Invalid email or password ❌");
      } else if (error.response.status === 403) {
        setErrorMessage("Access forbidden. Account may be disabled.");
      } else if (error.response.status === 404) {
        setErrorMessage("Login endpoint not found. Check server URL.");
      } else if (error.response.status === 400) {
        // Show specific validation errors
        const data = error.response.data;
        if (data.email) {
          setErrorMessage(`Email error: ${data.email.join(", ")}`);
        } else if (data.password) {
          setErrorMessage(`Password error: ${data.password.join(", ")}`);
        } else if (data.error) {
          setErrorMessage(data.error);
        } else if (data.non_field_errors) {
          setErrorMessage(data.non_field_errors.join(", "));
        } else {
          setErrorMessage("Invalid input. Please check your credentials.");
        }
      } else if (error.response.status === 500) {
        setErrorMessage("Server error. Please try again later.");
      } else {
        setErrorMessage(`Login failed: ${error.response?.data?.error || "Unknown error"}`);
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-container">
      <div className="auth-card">
        <h2>Login</h2>

        {errorMessage && (
          <div className="error-message" style={{
            backgroundColor: "#ffebee",
            color: "#c62828",
            padding: "10px",
            borderRadius: "4px",
            marginBottom: "15px",
            fontSize: "14px"
          }}>
            {errorMessage}
          </div>
        )}

        <form onSubmit={handleSubmit}>
          <input
            type="email"
            placeholder="Email"
            required
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            disabled={loading}
          />

          <input
            type="password"
            placeholder="Password"
            required
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            disabled={loading}
          />

          <button 
            type="submit" 
            disabled={loading}
            style={{
              opacity: loading ? 0.7 : 1,
              cursor: loading ? "not-allowed" : "pointer"
            }}
          >
            {loading ? "Logging in..." : "Login"}
          </button>
        </form>

        <p>
          Don't have an account?{" "}
          <span 
            onClick={() => navigate("/register")}
            style={{ 
              color: "#2f855a", 
              cursor: "pointer",
              textDecoration: "underline"
            }}
          >
            Register
          </span>
        </p>
      </div>
    </div>
  );
}
